    if user.age < 18:
        return restricted_response(user)
    return full_response(user)

class SessionMiddleware:
    def __call__(self, environ, start_response):
        token = environ.get('HTTP_AUTHORIZATION', '').removeprefix('Bearer ')
        if token:
            user = User.from_jwt_token(token)  # May raise if token format unexpected
            environ['user'] = user
        return self.app(environ, start_response)

def login(request):
    user = authenticate(request.POST['username'], request.POST['password'])
    if user:
        token = generate_jwt(user)
        return JsonResponse({'token': token})  # Tests may still be sending cookie header

class UserService:
