class OrderService:
    def __init__(self, db, email_service):
        self.db = db
        self.email_service = email_service

    def create_order(self, data: dict) -> Order:
        order = Order(**data)
        self.db.save(order)
        self.email_service.send(
            recipient=order.user.email,
            template='order_confirmation',
            context={'order': order}
        )
        return order

