class JobQueue:
    def claim_next_job(self, worker_id: str) -> Optional[Job]:
        job = self.db.query('SELECT * FROM jobs WHERE status=? LIMIT 1', 'pending')
        if job:
            self.db.execute('UPDATE jobs SET status=?, worker_id=? WHERE id=?',
                          'processing', worker_id, job.id)
        return job  # Multiple workers can claim same job between SELECT and UPDATE
